import React from "react";
import dayjs from "dayjs";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

function Dashboard() {
  const adminProfile = {
    name: "Admin",
    lastUpdated: new Date(),
  };

  const summaryCards = {
    totalUsers: 1250,
    totalLeads: 842,
    totalRevenue: 2450000,
    totalSupportTickets: 128,
  };

  /* ================= PAYMENTS CHART (DUMMY DATA) ================= */

  const paymentLabels = [
    "Jan 2026",
    "Feb 2026",
    "Mar 2026",
    "Apr 2026",
    "May 2026",
    "Jun 2026",
  ];

  const clientData = [40, 55, 48, 70, 66, 80];
  const paymentData = [400000, 520000, 460000, 720000, 650000, 810000];

  const commissionPercent = 10;
  const commissionData = paymentData.map((amt) =>
    Number(((amt * commissionPercent) / 100).toFixed(0))
  );

  const paymentsChartData = {
    labels: paymentLabels,
    datasets: [
      {
        label: "Clients Converted",
        data: clientData,
        backgroundColor: "#0d6efd65",
        borderRadius: 8,
      },
      {
        label: "Payments (₹)",
        data: paymentData,
        backgroundColor: "#19875475",
        borderRadius: 8,
        yAxisID: "yAmount",
      },
      {
        label: "Commission (10%)",
        data: commissionData,
        backgroundColor: "#ffc10775",
        borderRadius: 8,
        yAxisID: "yAmount",
      },
    ],
  };

  const paymentsChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { position: "top" },
      title: {
        display: true,
        text: "Payments Overview (2026)",
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        title: { display: true, text: "Clients" },
      },
      yAmount: {
        position: "right",
        beginAtZero: true,
        grid: { drawOnChartArea: false },
        ticks: {
          callback: (value) => `₹${(value / 1000).toFixed(0)}k`,
        },
      },
    },
  };

  /* ================= LEAD STATUS CHART (DUMMY DATA) ================= */

  const leadLabels = [
    "Jan",
    "Feb",
    "Mar",
    "Apr",
    "May",
    "Jun",
  ];

  const leadChartData = {
    labels: leadLabels,
    datasets: [
      {
        label: "Total Leads",
        data: [120, 150, 130, 170, 160, 190],
        backgroundColor: "#0d6efd65",
        borderRadius: 8,
      },
      {
        label: "Approved Leads",
        data: [90, 110, 95, 130, 125, 150],
        backgroundColor: "#19875475",
        borderRadius: 8,
      },
      {
        label: "Duplicate Leads",
        data: [10, 15, 12, 18, 14, 20],
        backgroundColor: "#dc354575",
        borderRadius: 8,
      },
    ],
  };

  const leadChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { position: "top" },
      title: {
        display: true,
        text: "Lead Status (2026)",
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        ticks: {
          stepSize: 20,
        },
      },
    },
  };

  return (
    <div className="container py-3">
      {/* Header */}
      <div className="row g-2">
        <div className="col-12">
          <h4 className="fw-bold fs-3">Welcome, {adminProfile.name}</h4>
        </div>
        <div className="col-12">
          <small>
            Last Updated:{" "}
            {dayjs(adminProfile.lastUpdated).format("DD MMM YYYY, hh:mm A")}
          </small>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="row g-3 pt-3">
        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-primary border-opacity-50">
            <small>Total Users</small>
            <h5>{summaryCards.totalUsers}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-success border-opacity-50">
            <small>Total Leads</small>
            <h5>{summaryCards.totalLeads}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-warning border-opacity-50">
            <small>Total Revenue</small>
            <h5>₹{summaryCards.totalRevenue.toLocaleString("en-IN")}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-danger border-opacity-50">
            <small>Support Tickets</small>
            <h5>{summaryCards.totalSupportTickets}</h5>
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="row pt-4 g-4">
        {/* Lead Chart */}
        <div className="col-lg-4 col-12">
          <div
            className="border rounded p-3 bg-body"
            style={{ height: "350px" }}
          >
            <Bar data={leadChartData} options={leadChartOptions} />
          </div>
        </div>

        {/* Payments Chart */}
        <div className="col-lg-8 col-12">
          <div
            className="border rounded p-3 bg-body"
            style={{ height: "350px" }}
          >
            <Bar data={paymentsChartData} options={paymentsChartOptions} />
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
